var minDeletion = function(s, k) {
    const c = new Map();
    for (const ch of s) c.set(ch, (c.get(ch) || 0) + 1);
    const freqs = [...c.values()].sort((a, b) => a - b);
    const d = freqs.length;
    if (d <= k) return 0;
    let sum = 0;
    for (let i = 0; i < d - k; i++) sum += freqs[i];
    return sum;
};
